/**
 * Groth16 real verifier integration tests.
 *
 * Exercises the full cryptographic round-trip: real BN254 proof → real
 * Groth16Verifier on-chain pairing check → adapter extraction → acceptance.
 *
 * Uses a proof fixture generated by:
 *   node scripts/generate-groth16-fixture.mjs
 *
 * Unlike the mock-based tests, the ecPairing precompile executes for real.
 */

import { expect } from "chai";
import { ethers, upgrades } from "hardhat";
import * as fs from "fs";
import * as path from "path";
import {
  DOMAIN,
  PROGRAM_VKEY,
  POLICY_HASH,
  MAX_ACCEPTANCE_DELAY,
  GENESIS_L2_BLOCK,
  enablePermissionless,
  findEventLog
} from "./deployment-fixtures";

interface Groth16Fixture {
  publicOutputs: {
    stfCommitment: string;
    proverSetDigest: string;
  };
  proof: {
    pA: string[];
    pB: string[][];
    pC: string[];
  };
}

function loadFixture(): Groth16Fixture {
  const fixturePath = path.join(__dirname, "../fixtures/groth16-proof-fixture.json");
  return JSON.parse(fs.readFileSync(fixturePath, "utf-8"));
}

function encodeRealGroth16Proof(fixture: Groth16Fixture): string {
  return ethers.AbiCoder.defaultAbiCoder().encode(
    ["uint256[2]", "uint256[2][2]", "uint256[2]", "uint256", "uint256"],
    [
      fixture.proof.pA.map(BigInt),
      fixture.proof.pB.map((row) => row.map(BigInt)),
      fixture.proof.pC.map(BigInt),
      BigInt(fixture.publicOutputs.stfCommitment),
      BigInt(fixture.publicOutputs.proverSetDigest)
    ]
  );
}

function encodePublicInputsWithRealStf(
  l2Start: bigint,
  l2End: bigint,
  windowCloseTimestamp: bigint,
  realStfCommitment: string,
  domain: string = DOMAIN
): string {
  const submissionBinding = ethers.keccak256(
    ethers.AbiCoder.defaultAbiCoder().encode(
      ["uint256", "uint256", "bytes32", "bytes32", "bytes32", "uint256"],
      [l2Start, l2End, ethers.ZeroHash, ethers.ZeroHash, domain, windowCloseTimestamp]
    )
  );
  return ethers.AbiCoder.defaultAbiCoder().encode(
    ["bytes32", "uint256", "uint256", "bytes32", "bytes32", "bytes32", "uint256", "bytes32"],
    [
      realStfCommitment,
      l2Start,
      l2End,
      ethers.ZeroHash,
      ethers.ZeroHash,
      domain,
      windowCloseTimestamp,
      submissionBinding
    ]
  );
}

describe("Groth16 real verifier integration", function () {
  this.timeout(120_000);

  let fixture: Groth16Fixture;

  before(function () {
    fixture = loadFixture();
  });

  it("real Groth16Verifier accepts a genuine BN254 proof via adapter", async function () {
    const [owner] = await ethers.getSigners();

    const Verifier = await ethers.getContractFactory("Groth16Verifier", owner);
    const verifier = await Verifier.deploy();
    await verifier.waitForDeployment();

    const Adapter = await ethers.getContractFactory("Groth16ZkAdapter", owner);
    const adapter = await Adapter.deploy(await verifier.getAddress(), PROGRAM_VKEY, POLICY_HASH);
    await adapter.waitForDeployment();

    const envelope = encodeRealGroth16Proof(fixture);
    const result = await adapter.getFunction("verify(bytes,bytes)").staticCall(envelope, "0x");

    expect(result.valid).to.equal(true, "Real verifier must accept genuine proof");
    expect(result.stfCommitment).to.equal(fixture.publicOutputs.stfCommitment);
    expect(result.proverSetDigest).to.equal(fixture.publicOutputs.proverSetDigest);
  });

  it("real Groth16Verifier rejects corrupted proof via adapter", async function () {
    const [owner] = await ethers.getSigners();

    const Verifier = await ethers.getContractFactory("Groth16Verifier", owner);
    const verifier = await Verifier.deploy();
    await verifier.waitForDeployment();

    const Adapter = await ethers.getContractFactory("Groth16ZkAdapter", owner);
    const adapter = await Adapter.deploy(await verifier.getAddress(), PROGRAM_VKEY, POLICY_HASH);
    await adapter.waitForDeployment();

    // Corrupt pA[0]
    const badPa = [BigInt(fixture.proof.pA[0]) ^ 1n, BigInt(fixture.proof.pA[1])];
    const envelope = ethers.AbiCoder.defaultAbiCoder().encode(
      ["uint256[2]", "uint256[2][2]", "uint256[2]", "uint256", "uint256"],
      [
        badPa,
        fixture.proof.pB.map((row) => row.map(BigInt)),
        fixture.proof.pC.map(BigInt),
        BigInt(fixture.publicOutputs.stfCommitment),
        BigInt(fixture.publicOutputs.proverSetDigest)
      ]
    );

    await expect(adapter.getFunction("verify(bytes,bytes)").staticCall(envelope, "0x")).to.be
      .reverted;
  });

  it("full stack submission with real Groth16 proof through finalizer", async function () {
    const [owner] = await ethers.getSigners();

    const Verifier = await ethers.getContractFactory("Groth16Verifier", owner);
    const verifier = await Verifier.deploy();
    await verifier.waitForDeployment();

    const Adapter = await ethers.getContractFactory("Groth16ZkAdapter", owner);
    const adapter = await Adapter.deploy(await verifier.getAddress(), PROGRAM_VKEY, POLICY_HASH);
    await adapter.waitForDeployment();

    const Finalizer = await ethers.getContractFactory("WorldlineFinalizer", owner);
    const finalizer = await upgrades.deployProxy(
      Finalizer,
      [
        await adapter.getAddress(),
        DOMAIN,
        MAX_ACCEPTANCE_DELAY,
        GENESIS_L2_BLOCK,
        ethers.ZeroAddress
      ],
      { kind: "uups", initializer: "initialize" }
    );
    await finalizer.waitForDeployment();
    await enablePermissionless(finalizer);

    const l2Start = GENESIS_L2_BLOCK;
    const l2End = 100n;
    const block = await ethers.provider.getBlock("latest");
    const windowCloseTimestamp = BigInt(block!.timestamp) + 7200n;

    const proof = encodeRealGroth16Proof(fixture);
    const publicInputs = encodePublicInputsWithRealStf(
      l2Start,
      l2End,
      windowCloseTimestamp,
      fixture.publicOutputs.stfCommitment,
      DOMAIN
    );

    const tx = await (finalizer as any).submitZkValidityProof(proof, publicInputs);
    const receipt = await tx.wait();

    const event = findEventLog(receipt, (finalizer as any).interface, "ZkProofAccepted");
    expect(event).to.not.be.null;
    expect(event.args.windowIndex).to.equal(0n);
  });
});
